final:
module full_adder(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);

wire carry_inverted, w2, w3;

// Calculate SUM
assign carry_inverted = A ^ B;
assign SUM = carry_inverted ^ CIN;

// Calculate COUT
assign w2 = A & B;
assign w3 = CIN & carry_inverted;
assign COUT = w2 | w3;

endmodule
